useEffect(() => {
  const interval = setInterval(() => {
    setTemps(prev => {
      if (prev <= 1) {
        clearInterval(interval);
        passerQuestion();
        return 0;
      }
      return prev - 1;
    });
  }, 1000);
  return () => clearInterval(interval);
}, []);

useEffect(() => {
  const ws = new WebSocket('ws://localhost:8080');

  ws.onmessage = (event) => {
    const message = JSON.parse(event.data);
    setMessages(prev => [...prev, message]);
  };

  return () => {
    ws.close();
  };
}, []);

useEffect(() => {
  setLoading(true);
  fetch(`https://api.meteo.com/${ville}`)
    .then(res => res.json())
    .then(data => { setData(data); setLoading(false); })
    .catch(err => { setError(err); setLoading(false); });
}, [ville]);

useEffect(() => {
  const controller = new AbortController();
  setLoading(true);
  fetch(`https://api.meteo.com/${ville}`, { signal: controller.signal })
    .then(res => res.json())
    .then(data => { setData(data); setLoading(false); })
    .catch(err => {
      if (err.name !== 'AbortError') {
        setError(err);
        setLoading(false);
      }
    });
  return () => controller.abort();
}, [ville]);

useEffect(() => {
  const subscription = LightSensor.addListener(({ illuminance }) => {
    setLuminosite(illuminance);
  });
  return () => subscription.remove();
}, []);

useEffect(() => {
  const subscription = LightSensor.addListener(({ illuminance }) => {
    setLuminosite(illuminance);
    const nouveauTheme = illuminance < 50 ? 'dark' : 'light';
    setTheme(nouveauTheme);
  });
  return () => subscription.remove();
}, []);
